import React, { useState, useEffect, useRef } from 'react';
import { Mic, PhoneOff, Settings, Volume2, ShieldCheck, Activity, Hexagon, Loader2, Sparkles } from 'lucide-react';

const VoicePage: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<"Listening" | "Thinking" | "Responding" | "Idle">("Idle");
  const [bars, setBars] = useState(new Array(40).fill(5));

  useEffect(() => {
    let interval: number;
    if (isActive) {
      interval = window.setInterval(() => {
        setBars(new Array(40).fill(0).map(() => Math.random() * (status === "Responding" ? 80 : 30) + 10));
      }, 100);
    } else {
      setBars(new Array(40).fill(5));
    }
    return () => clearInterval(interval);
  }, [isActive, status]);

  const toggleVoice = () => {
    if (isActive) {
      setIsActive(false);
      setStatus("Idle");
    } else {
      setIsActive(true);
      setStatus("Listening");
      setTimeout(() => setStatus("Thinking"), 3000);
      setTimeout(() => setStatus("Responding"), 5000);
    }
  };

  return (
    <div className="relative min-h-[calc(100vh-80px)] flex flex-col items-center justify-center bg-[#0B0B0F] overflow-hidden">
      {/* Background Pulse */}
      <div className={`absolute inset-0 bg-radial-gradient from-[#E10600]/5 to-transparent transition-opacity duration-1000 ${isActive ? 'opacity-100' : 'opacity-0'}`}></div>
      <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

      {/* Central Waveform Section */}
      <div className="relative z-10 flex flex-col items-center gap-12 max-w-4xl w-full px-6 text-center">
        <div className="space-y-4">
           <div className={`inline-flex items-center gap-2 px-4 py-2 border rounded-full transition-all duration-500 ${isActive ? 'border-[#E10600]/40 bg-[#E10600]/10 text-[#E10600]' : 'border-white/10 bg-white/5 text-slate-500'}`}>
              <div className={`size-2 rounded-full ${isActive ? 'bg-[#E10600] animate-ping' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-black uppercase tracking-[0.4em]">{status}</span>
           </div>
           <h1 className="text-4xl lg:text-6xl font-black uppercase tracking-tighter text-white">
              SPEAK NATURALLY. <br/>
              <span className="text-[#E10600]">KRYPTON AI UNDERSTANDS.</span>
           </h1>
        </div>

        <div className="relative h-64 flex items-center justify-center gap-1.5 w-full">
          {bars.map((h, i) => (
            <div 
              key={i} 
              className={`w-1.5 rounded-full transition-all duration-150 ${isActive ? 'bg-[#E10600] shadow-[0_0_15px_#E10600]' : 'bg-white/5'}`}
              style={{ height: `${h}%`, opacity: isActive ? 0.4 + (h / 100) : 0.1 }}
            ></div>
          ))}
          {isActive && (
            <div className="absolute inset-0 flex items-center justify-center -z-10">
               <div className="size-[400px] bg-[#E10600]/10 blur-[100px] rounded-full animate-pulse"></div>
            </div>
          )}
        </div>

        <div className="max-w-xl">
           <p className="text-slate-500 text-sm font-medium uppercase tracking-widest leading-relaxed">
             You are talking to a senior business advisor. Krypton AI is specialized in strategic closing and complex diagnostic.
           </p>
        </div>
      </div>

      {/* Control Bar */}
      <div className="absolute bottom-20 flex justify-center w-full z-20">
        <div className="bg-[#1A1A1F]/80 backdrop-blur-3xl border border-white/10 p-4 rounded-full flex items-center gap-6 shadow-2xl red-glow">
          <button className="size-14 flex items-center justify-center text-slate-500 hover:text-white transition-all hover:bg-white/5 rounded-full">
            <Settings size={20} />
          </button>

          <button 
            onClick={toggleVoice}
            className={`relative size-24 rounded-full flex items-center justify-center transition-all shadow-2xl active:scale-95 ${
              isActive 
              ? 'bg-white text-[#E10600] hover:scale-105' 
              : 'bg-[#E10600] text-white hover:bg-red-700 hover:scale-110'
            }`}
          >
            {isActive ? <PhoneOff size={32} /> : <Mic size={32} />}
            {isActive && <div className="absolute -inset-4 border border-[#E10600]/20 rounded-full animate-ping"></div>}
          </button>

          <button className="size-14 flex items-center justify-center text-slate-500 hover:text-white transition-all hover:bg-white/5 rounded-full">
            <Volume2 size={20} />
          </button>
        </div>
      </div>

      {/* Status Badges */}
      <div className="absolute bottom-10 left-10 flex gap-4 opacity-50">
         <div className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-slate-500">
            <ShieldCheck size={12} /> Encrypted Liaison
         </div>
         <div className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-slate-500">
            <Activity size={12} /> Real-time Inference
         </div>
      </div>
    </div>
  );
};

