import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { X, Mic, PhoneOff, Bot, ShieldCheck, Activity, Hexagon, Loader2, Volume2, Settings, AlertTriangle, RefreshCw, Zap, Target } from 'lucide-react';
import { Agent } from '../types';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [isConnecting, setIsConnecting] = useState(true);
  const [isActive, setIsActive] = useState(false);
  const [isWaitingForKeyword, setIsWaitingForKeyword] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [statusText, setStatusText] = useState("INITIALIZING UNIT...");
  const [leadScore, setLeadScore] = useState(0);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const retryCountRef = useRef(0);
  const isClosingRef = useRef(false);
  const failsafeTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (agent) {
      startVocalSession();
    }
    return () => {
      if (failsafeTimeoutRef.current) window.clearTimeout(failsafeTimeoutRef.current);
      stopSession();
    };
  }, [agent]);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const activateVoice = () => {
    if (!isWaitingForKeyword) return;
    if (failsafeTimeoutRef.current) window.clearTimeout(failsafeTimeoutRef.current);

    setIsWaitingForKeyword(false);
    setStatusText("STRATEGIC DIAGNOSTIC ACTIVE");

    if (sessionRef.current) {
      sessionRef.current.sendRealtimeInput({ text: "Activation confirmed. Speak now and introduce yourself as the Strategic Director. Start the diagnostic." });
    }
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStatusText("SYNCHRONIZING NEURAL CORE...");

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatusText("LIAISON ESTABLISHED — SAY OK KRYPTON");
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              if (isWaitingForKeyword) {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 20) + 5));
              } else {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 85) + 10));
              }

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // ANTI-SILENCE WATCHDOG: Force activation if user says nothing after 2s
            failsafeTimeoutRef.current = window.setTimeout(() => {
              console.log("Watchdog: Triggering failsafe voice introduction.");
              activateVoice();
            }, 2000);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // Trigger detection
            if (isWaitingForKeyword && message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text.toLowerCase();
              if (text.includes("krypton") || text.includes("ok") || text.includes("bonjour")) {
                activateVoice();
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              setStatusText("AI RESPONDING...");
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) {
                  setBars(new Array(40).fill(10));
                  setStatusText("AI LISTENING...");
                }
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 5, 99));
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Neural Liaison Error:', e);
            if (retryCountRef.current < 2 && !isClosingRef.current) {
              retryCountRef.current++;
              setTimeout(startVocalSession, 1500);
            } else {
              setError("Liaison neurale rompue.");
              stopSession();
            }
          },
          onclose: () => { if (!isClosingRef.current) stopSession(); }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("Accès microphone refusé.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    if (sessionRef.current) sessionRef.current.close();

    setBars(new Array(40).fill(5));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-[#0B0B0F]/98 backdrop-blur-3xl flex flex-col items-center justify-center animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>

      {/* Header */}
      <div className="absolute top-12 w-full px-12 flex justify-between items-center z-20">
        <div className="flex items-center gap-6">
          <div className="size-16 bg-[#E10600]/10 border border-[#E10600]/30 flex items-center justify-center rounded-sm">
            <Bot className="text-[#E10600]" size={32} />
          </div>
          <div>
            <h3 className="text-2xl font-black uppercase tracking-tighter">{agent.name}</h3>
            <p className="text-[10px] font-black text-[#E10600] uppercase tracking-[0.4em] mt-1 italic">Vocal Core v4.0 Active</p>
          </div>
        </div>
        <button onClick={onClose} className="size-14 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white/10 transition-all text-slate-400 group">
          <X size={28} className="group-hover:rotate-90 transition-transform" />
        </button>
      </div>

      {/* Visual Area */}
      <div className="relative w-full max-w-4xl flex flex-col items-center justify-center h-[400px]">
        {isWaitingForKeyword && !isConnecting && (
          <div className="absolute top-0 z-30 flex flex-col items-center text-center animate-in fade-in duration-700">
            <p className="text-lg font-light tracking-[0.5em] text-slate-500 uppercase mb-4">Initialisation du dialogue</p>
            <h4 className="text-4xl lg:text-7xl font-black uppercase tracking-tighter text-white">
              SAY <span className="text-[#E10600] italic">“OK KRYPTON”</span>
            </h4>
          </div>
        )}

        <div className="relative z-10 flex items-end gap-2 h-64">
          {bars.map((height, i) => (
            <div key={i} className={`w-1.5 md:w-2 rounded-full transition-all duration-300 ${isActive ? (isWaitingForKeyword ? 'bg-white/10' : 'bg-[#E10600] shadow-[0_0_20px_#E10600]') : 'bg-slate-800'}`} 
              style={{ height: `${height}%`, opacity: isActive ? (height / 100) * 0.5 + 0.5 : 0.2 }}></div>
          ))}
        </div>

        {isActive && !isWaitingForKeyword && (
          <div className="absolute size-96 bg-[#E10600]/5 blur-[120px] rounded-full animate-pulse pointer-events-none"></div>
        )}
      </div>

      <div className="absolute bottom-20 w-full flex flex-col items-center gap-12 z-20">
        <div className="text-center">
           <p className={`text-[11px] font-black uppercase tracking-[0.5em] ${isActive ? 'text-[#E10600]' : 'text-slate-600'}`}>{statusText}</p>
           <div className="flex gap-8 mt-4 opacity-30 text-[9px] font-black uppercase tracking-widest text-slate-500">
              <span className="flex items-center gap-2"><Activity size={12}/> Latency: 14ms</span>
              <span className="flex items-center gap-2"><Target size={12}/> Intent Score: {leadScore}%</span>
           </div>
        </div>
        <div className="bg-[#1A1A1F]/80 backdrop-blur-2xl border border-white/10 p-5 rounded-full flex items-center gap-8 shadow-2xl">
          <button className="size-14 flex items-center justify-center text-slate-500 hover:text-white rounded-full"><Settings size={22} /></button>
          <button 
            onClick={isActive ? stopSession : startVocalSession} 
            disabled={isConnecting} 
            className={`relative size-24 rounded-full flex items-center justify-center transition-all ${isActive ? 'bg-white text-[#E10600]' : 'bg-[#E10600] text-white shadow-xl shadow-red-500/20'}`}
          >
            {isConnecting ? <Loader2 className="size-10 animate-spin" /> : isActive ? <PhoneOff size={36} /> : <Mic size={36} />}
            {isActive && <div className="absolute -inset-4 border border-[#E10600]/20 rounded-full animate-ping pointer-events-none"></div>}
          </button>
          <button className="size-14 flex items-center justify-center text-slate-600 hover:text-white rounded-full"><Volume2 size={22} /></button>
        </div>
      </div>

      {error && (
        <div className="fixed top-32 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-6 rounded-sm flex items-center gap-4 shadow-2xl">
          <AlertTriangle className="text-white" size={24} />
          <p className="text-[10px] font-black uppercase tracking-widest text-white">{error}</p>
        </div>
      )}
    </div>
  );
};

