import React, { useState } from 'react';
import { Page } from './types';
import { GLOBAL_ADVISOR } from './constants';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import AgentsPage from './pages/AgentsPage';
import VoicePage from './pages/VoicePage';
import CRMPage from './pages/CRMPage';
import ScraperPage from './pages/ScraperPage';
import TrustPage from './pages/TrustPage';
import AIChatOverlay from './components/AIChatOverlay';
import { MessageSquareText } from 'lucide-react';

const App: React.FC = () => {
  // Routing state
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [globalAdvisorOpen, setGlobalAdvisorOpen] = useState(false);

  const navigateTo = (page: Page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <HomePage onNavigate={navigateTo} />;
      case Page.AGENTS: return <AgentsPage />;
      case Page.VOICE: return <VoicePage />;
      case Page.CRM: return <CRMPage />;
      case Page.SCRAPER: return <ScraperPage />;
      case Page.TRUST: return <TrustPage />;
      default: return <HomePage onNavigate={navigateTo} />;
    }
  };

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex flex-col selection:bg-[#E10600] selection:text-white font-sans overflow-x-hidden">
      {/* Navbar with pure state navigation */}
      <Navbar 
        activePage={currentPage} 
        onNavigate={navigateTo}
        onLaunch={() => navigateTo(Page.CRM)} 
      />

      {/* Main container without global padding-top to allow hero to touch header */}
      <main className="flex-grow">
        {renderPage()}
      </main>

      <Footer onNavigate={navigateTo} />

      {/* Global AI Advisor Trigger - Text/Strategic Reasoning focused */}
      <button 
        onClick={() => setGlobalAdvisorOpen(true)}
        className="fixed bottom-8 right-8 z-50 group flex flex-row-reverse items-center gap-4 bg-[#0B0B0F]/90 backdrop-blur-md border border-[#E10600]/30 p-2 pl-6 rounded-full hover:border-[#E10600] transition-all shadow-[0_0_30px_rgba(225,6,0,0.2)] hover:scale-105 active:scale-95"
      >
        <div className="size-12 bg-[#E10600] flex items-center justify-center rounded-full text-white shadow-lg shadow-red-500/40 group-hover:rotate-12 transition-transform">
          <MessageSquareText size={24} />
        </div>
        <div className="text-right hidden sm:block">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] text-[#E10600]">Directeur de Stratégie</p>
          <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">IA Krypton en ligne</p>
        </div>
      </button>

      {globalAdvisorOpen && (
        <AIChatOverlay 
          agent={GLOBAL_ADVISOR} 
          onClose={() => setGlobalAdvisorOpen(false)} 
        />
      )}
    </div>
  );
};

