import React, { useState, useRef, useEffect } from 'react';
import { Mic, PhoneOff, AlertTriangle, Activity, Hexagon, RefreshCw, Loader2, Volume2, Settings } from 'lucide-react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoicePage: React.FC = () => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<'Listening' | 'Thinking' | 'Responding' | 'Ready'>('Ready');
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(10));

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => stopSession();
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStatus('Ready');

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatus('Listening');

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              // Update visual bars based on input
              setBars(prev => prev.map(() => Math.floor(Math.random() * 80) + 10));

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            if (message.serverContent?.modelTurn) {
              setStatus('Responding');
            } else if (message.serverContent?.turnComplete) {
              setStatus('Listening');
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(40).fill(10));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error('Link Error:', e);
            setError("Échec de la connexion. Service momentanément indisponible.");
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: 'Vous êtes un conseiller commercial senior. Parlez naturellement, écoutez attentivement et guidez le client avec assurance.'
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("Accès microphone refusé.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);
    setStatus('Ready');

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    if (sessionRef.current) sessionRef.current.close();

    setBars(new Array(40).fill(10));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  };

  return (
    <div className="relative h-[calc(100vh-80px)] overflow-hidden bg-[#0B0B0F] flex flex-col items-center justify-center pt-20">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>
      <div className="absolute inset-0 bg-gradient-to-b from-[#E10600]/5 to-transparent pointer-events-none"></div>

      {/* Waveform Visualization */}
      <div className="relative w-full max-w-4xl flex flex-col items-center justify-center">
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-20">
          <Hexagon size={600} className="text-[#E10600]/10 animate-[spin_80s_linear_infinite]" strokeWidth={0.5} />
          <Hexagon size={400} className="absolute text-[#E10600]/20 animate-[spin_40s_linear_infinite_reverse]" strokeWidth={1} />
        </div>

        <div className="relative z-10 flex items-end gap-2 h-64 mb-12">
          {bars.map((height, i) => (
            <div 
              key={i} 
              className={`w-2 md:w-3 rounded-full transition-all duration-150 ${isActive ? 'bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_20px_rgba(225,6,0,0.4)]' : 'bg-white/5'}`} 
              style={{ 
                height: `${height}%`,
                opacity: isActive ? (height / 100) * 0.7 + 0.3 : 0.2
              }}
            ></div>
          ))}
        </div>

        <div className="text-center mb-20 animate-in fade-in duration-1000">
           <p className="text-xl font-light tracking-[0.4em] uppercase text-white/60 mb-4">
              {isActive ? (status === 'Listening' ? 'Je vous écoute...' : status === 'Thinking' ? 'Analyse en cours...' : 'Réponse en cours...') : 'Système en Veille'}
           </p>
           <h2 className="text-4xl font-black uppercase tracking-widest text-white">
              {isActive ? status : 'Prêt pour l\'appel'}
           </h2>
        </div>
      </div>

      {/* Interface Controls */}
      <div className="bg-[#1A1A1F]/40 backdrop-blur-3xl border border-white/5 p-6 rounded-full flex items-center gap-10 shadow-2xl relative z-20">
        <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white transition-all"><Settings size={24} /></button>

        <button 
          onClick={isActive ? stopSession : startSession}
          disabled={isConnecting}
          className={`relative size-28 rounded-full flex items-center justify-center transition-all shadow-2xl active:scale-90 ${
            isActive ? 'bg-white text-[#E10600]' : 'bg-[#E10600] text-white hover:bg-red-700'
          }`}
        >
          {isConnecting ? <Loader2 className="size-10 animate-spin" /> : isActive ? <PhoneOff size={42} /> : <Mic size={42} />}
          {isActive && <div className="absolute -inset-4 border border-[#E10600]/20 rounded-full animate-ping pointer-events-none"></div>}
        </button>

        <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white transition-all"><Volume2 size={24} /></button>
      </div>

      {error && (
        <div className="mt-12 animate-in slide-in-from-bottom-4 bg-[#E10600] p-4 flex items-center gap-4 rounded-sm shadow-2xl">
           <AlertTriangle size={20} />
           <p className="text-[10px] font-black uppercase tracking-widest">{error}</p>
           <button onClick={startSession} className="underline text-[10px] font-black uppercase tracking-widest ml-4 flex items-center gap-2">
              <RefreshCw size={12}/> Réessayer
           </button>
        </div>
      )}
    </div>
  );
};

