function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [isConnecting, setIsConnecting] = useState(true);
  const [isActive, setIsActive] = useState(false);
  const [isWaitingForKeyword, setIsWaitingForKeyword] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [statusText, setStatusText] = useState("SYNCHRONISATION...");
  const [leadScore, setLeadScore] = useState(0);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const retryCountRef = useRef(0);
  const isClosingRef = useRef(false);
  const failsafeTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (agent) {
      startVocalSession();
    }
    return () => {
      if (failsafeTimeoutRef.current) window.clearTimeout(failsafeTimeoutRef.current);
      stopSession();
    };
  }, [agent]);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const activateVoice = () => {
    if (!isWaitingForKeyword) return;
    if (failsafeTimeoutRef.current) window.clearTimeout(failsafeTimeoutRef.current);

    setIsWaitingForKeyword(false);
    setStatusText("MASTER CLOSER FIKO EN LIGNE");

    // Trigger the agent introduction
    if (sessionRef.current) {
      sessionRef.current.sendRealtimeInput({ text: "L'activation est confirmée par OK FIKO. Présentez-vous comme FIKO, le Directeur Commercial et commencez le diagnostic selon vos scripts officiels." });
    }
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStatusText("SYNCHRONISATION NEURALE...");

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatusText("VOIX FIKO PRÊTE");
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              if (isWaitingForKeyword) {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 20) + 5));
              } else {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 80) + 10));
              }

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // START FAILSAFE TIMEOUT: 2.5 seconds max silence before proactive trigger
            failsafeTimeoutRef.current = window.setTimeout(() => {
              console.log("Krypton Failsafe: Triggering FIKO proactively.");
              activateVoice();
            }, 2500);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // Handle Trigger detection via transcription for "OK FIKO"
            if (isWaitingForKeyword && message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text.toLowerCase();
              if (text.includes("fiko") || text.includes("ok") || text.includes("okay")) {
                activateVoice();
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(40).fill(10));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 3, 98));
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Krypton Voice Error:', e);
            if (retryCountRef.current < 2 && !isClosingRef.current) {
              retryCountRef.current++;
              setStatusText("RECONNEXION...");
              setTimeout(startVocalSession, 2000);
            } else {
              setError("Liaison neurale FIKO instable. Relancez l'agent.");
              stopSession();
            }
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("Erreur technique de liaison FIKO.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(err => console.warn('AudioContext close error:', err));
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    setBars(new Array(40).fill(5));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black/98 backdrop-blur-3xl flex flex-col items-center justify-center animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>

      {/* HUD Header */}
      <div className="absolute top-12 w-full px-12 flex justify-between items-start z-20">
        <div className="flex items-center gap-6">
          <div className="size-16 bg-[#E10600]/10 border border-[#E10600]/30 flex items-center justify-center rounded-sm">
            <Bot className="text-[#E10600]" size={32} />
          </div>
          <div>
            <h3 className="text-3xl font-black uppercase tracking-tighter leading-none">{agent.name} (FIKO)</h3>
            <p className="text-[10px] font-black text-[#E10600] uppercase tracking-[0.3em] mt-1 italic flex items-center gap-2">
              <Zap size={10} fill="currentColor"/> Master Closer FIKO Active
            </p>
          </div>
        </div>

        <div className="flex gap-8">
          <div className="hidden lg:flex flex-col items-end">
            <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Analyse d'Intention</p>
            <div className="flex items-center gap-3">
              <span className="text-2xl font-black text-white">{leadScore}%</span>
              <div className="w-32 h-1 bg-white/5 rounded-full overflow-hidden">
                <div className="h-full bg-[#E10600] transition-all duration-700" style={{ width: `${leadScore}%` }}></div>
              </div>
            </div>
          </div>
          <button onClick={onClose} className="size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white/10 transition-all text-slate-400 group">
            <X size={36} className="group-hover:rotate-90 transition-transform" />
          </button>
        </div>
      </div>

      {/* Visual Waveform Area */}
      <div className="relative w-full max-w-6xl flex flex-col items-center justify-center h-[500px]">
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none overflow-hidden opacity-20">
          <Hexagon size={800} className="text-[#E10600]/10 animate-[spin_120s_linear_infinite]" strokeWidth={0.2} />
          <Hexagon size={400} className="absolute text-[#E10600]/30 animate-[spin_40s_linear_infinite]" strokeWidth={1} />
        </div>

        {/* Keyword Instruction Message - Updated for FIKO */}
        {isWaitingForKeyword && !isConnecting && (
          <div className="absolute top-0 z-30 animate-in zoom-in fade-in duration-500 flex flex-col items-center text-center">
            <div className="flex items-center gap-4 mb-6">
              <Mic className="text-[#E10600] animate-pulse" size={24} />
              <p className="text-xl font-bold uppercase tracking-[0.3em] text-white">Voix FIKO prête</p>
            </div>
            <h4 className="text-4xl lg:text-6xl font-black uppercase tracking-tighter text-white/90">
              Dites <span className="text-[#E10600] italic">“OK FIKO”</span> <br/>
              <span className="text-lg font-light tracking-[0.5em] text-slate-500">pour démarrer la conversation stratégique</span>
            </h4>
          </div>
        )}

        <div className="relative z-10 flex items-end gap-3 h-80 pt-20">
          {bars.map((height, i) => (
            <div key={i} className={`w-2 md:w-3 rounded-full transition-all duration-200 ${isActive ? (isWaitingForKeyword ? 'bg-white/20' : 'bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_20px_rgba(225,6,0,0.6)]') : 'bg-slate-800 opacity-20'}`} 
              style={{ height: `${height}%`, opacity: isActive ? (height / 100) * 0.6 + 0.4 : 0.2 }}></div>
          ))}
        </div>
        {isActive && !isWaitingForKeyword && <div className="absolute size-96 bg-[#E10600]/5 blur-[120px] rounded-full animate-pulse-red pointer-events-none"></div>}
      </div>

      {/* Status & Controls */}
      <div className="absolute bottom-20 w-full flex flex-col items-center gap-10 z-20">
        <div className="text-center">
           <p className={`text-[12px] font-black uppercase tracking-[0.5em] transition-all duration-700 ${isActive ? 'text-[#E10600]' : 'text-slate-600'}`}>{statusText}</p>
           <div className="flex justify-center gap-8 mt-4 opacity-40 text-[9px] font-mono uppercase text-slate-500">
              <span className="flex items-center gap-2"><Activity size={10}/> Latence: 14ms</span>
              <span className="flex items-center gap-2"><ShieldCheck size={10}/> FIKO Core v1.0</span>
              <span className="flex items-center gap-2"><Target size={10}/> Intent Level: {leadScore > 70 ? 'HIGH' : 'ANALYZING'}</span>
           </div>
        </div>
        <div className="bg-[#1A1A1F]/60 backdrop-blur-3xl border border-white/10 p-6 rounded-full flex items-center gap-8 shadow-2xl">
          <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white hover:bg-white/5 rounded-full"><Settings size={24} /></button>
          <button onClick={isActive ? stopSession : startVocalSession} disabled={isConnecting} className={`relative size-28 rounded-full flex items-center justify-center transition-all shadow-2xl active:scale-95 group ${isActive ? 'bg-white text-[#E10600]' : 'bg-[#E10600] text-white shadow-red-500/20'}`}>
            {isConnecting ? <Loader2 className="size-12 animate-spin" /> : isActive ? <PhoneOff size={42} /> : <Mic size={42} />}
            {isActive && <div className="absolute -inset-6 border border-[#E10600]/30 rounded-full animate-ping pointer-events-none"></div>}
          </button>
          <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white hover:bg-white/5 rounded-full"><Volume2 size={24} /></button>
        </div>
      </div>

      {error && (
        <div className="fixed top-32 left-1/2 -translate-x-1/2 z-[110] animate-in slide-in-from-top-4">
          <div className="bg-[#E10600] p-6 rounded-sm flex items-center gap-6 shadow-[0_0_50px_rgba(225,6,0,0.4)]">
            <AlertTriangle className="text-white" size={32} />
            <div>
              <p className="text-[12px] font-black uppercase tracking-widest text-white">{error}</p>
              <button onClick={() => { setError(null); startVocalSession(); }} className="flex items-center gap-2 text-[10px] font-black uppercase text-white/70 hover:text-white underline mt-2"><RefreshCw size={12}/> Réessayer</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

