  useEffect(() => {
    if (agent && messages.length === 0) {
      setMessages([{ 
        role: 'model', 
        text: `Très bien. Je suis FIKO, le Directeur Commercial Virtuel de Krypton AI. Avant qu'on ne parle de solutions, j'aimerais comprendre : quel est le plus gros goulot d'étranglement qui freine votre croissance aujourd'hui ?` 
      }]);
    }
  }, [agent]);

