function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

enum FikoStep {
  PRE_START = 'pre_start',
  KEYWORD = 'keyword',
  CONVERSATION = 'conversation'
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [step, setStep] = useState<FikoStep>(FikoStep.PRE_START);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [statusText, setStatusText] = useState("EN ATTENTE");
  const [leadScore, setLeadScore] = useState(0);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const retryCountRef = useRef(0);
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => stopSession();
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStep(FikoStep.KEYWORD);
    setStatusText("SYNCHRONISATION...");

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatusText("MICRO ACTIF");
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              if (step === FikoStep.KEYWORD) {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 10) + 2));
              } else {
                setBars(prev => prev.map(() => Math.floor(Math.random() * 80) + 10));
              }

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // Trigger detection via transcription for "OK FIKO"
            if (step === FikoStep.KEYWORD && message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text.toLowerCase();
              if (text.includes("fiko") || text.includes("ok")) {
                setStep(FikoStep.CONVERSATION);
                setStatusText("FIKO EN LIGNE");
                sessionRef.current?.sendRealtimeInput({ text: "L'utilisateur a dit OK FIKO. Lance ton introduction brutale immédiatement : 'Très bien. Je suis FIKO. Avant de vous expliquer quoi que ce soit… je vais vous poser une question simple. Aujourd’hui… est-ce que votre site vous apporte des clients régulièrement ?'" });
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(40).fill(10));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 5, 100));
            }
          },
          onerror: (e) => {
            console.error('Krypton Voice Error:', e);
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError("Accès micro refusé.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(() => {});
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
    }

    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  };

  const handleClose = () => {
    // Brutal message on exit as requested
    console.log("La conversation s’arrête ici. Vos concurrents, eux, continuent.");
    onClose();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-700 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-5"></div>

      {/* Step 1: Pre-Activation Screen */}
      {step === FikoStep.PRE_START && (
        <div className="max-w-2xl w-full text-center space-y-12 animate-in fade-in zoom-in duration-700 relative z-10">
          <div className="inline-flex items-center gap-4 px-6 py-2 border border-[#E10600]/30 bg-[#E10600]/5 text-[#E10600] text-[10px] font-black uppercase tracking-[0.5em] mb-4">
             ATTENTION : MOMENT DE VÉRITÉ
          </div>
          <h2 className="text-4xl lg:text-7xl font-black uppercase tracking-tighter leading-none text-white">
            Vous êtes sur le point <br/>de parler à <span className="text-[#E10600]">FIKO.</span>
          </h2>
          <p className="text-xl lg:text-3xl text-slate-500 font-light italic leading-relaxed uppercase tracking-widest border-l-2 border-[#E10600] pl-10 text-left mx-auto">
            Directeur Commercial Virtuel de Krypton AI. <br/>
            <span className="text-slate-400 mt-4 block">Cette conversation peut remettre en question votre manière de vendre.</span>
          </p>
          <div className="pt-12">
            <button 
              onClick={startVocalSession}
              disabled={isConnecting}
              className="group relative bg-[#E10600] text-white px-20 py-10 rounded-sm font-black text-xs transition-all uppercase tracking-[0.6em] shadow-[0_0_60px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto"
            >
              {isConnecting ? <Loader2 className="animate-spin" size={24} /> : <>🎙️ Démarrer avec FIKO <ArrowRight size={20} className="group-hover:translate-x-3 transition-transform" /></>}
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Waiting for trigger */}
      {step === FikoStep.KEYWORD && (
        <div className="flex flex-col items-center gap-20 animate-in zoom-in duration-1000">
          <div className="relative">
             <div className="absolute inset-0 bg-[#E10600]/20 blur-[100px] rounded-full animate-pulse"></div>
             <Mic className="text-[#E10600] relative z-10 size-40 animate-pulse" strokeWidth={1} />
          </div>
          <div className="text-center space-y-6">
            <h3 className="text-4xl lg:text-8xl font-black uppercase tracking-tighter text-white/90">
              Dites <span className="text-[#E10600] italic">“OK FIKO”</span>
            </h3>
            <p className="text-sm font-black uppercase tracking-[0.6em] text-slate-600 animate-pulse">
              Le système attend votre signal pour l'activation neurale
            </p>
          </div>
          <div className="flex gap-2">
            {bars.map((h, i) => (
              <div key={i} className="w-1.5 h-12 bg-white/5 rounded-full overflow-hidden">
                <div className="w-full bg-[#E10600]/40 transition-all duration-200" style={{ height: `${h}%` }}></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Step 3: Conversation Active */}
      {step === FikoStep.CONVERSATION && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-6xl relative animate-in fade-in duration-1000">
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-20 pointer-events-none">
              <Hexagon size={800} className="text-[#E10600]/10 animate-[spin_100s_linear_infinite]" strokeWidth={0.2} />
           </div>

           <div className="relative z-10 flex items-end gap-3 h-80 pt-20">
            {bars.map((height, i) => (
              <div key={i} className={`w-3 md:w-4 rounded-full transition-all duration-200 bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_20px_rgba(225,6,0,0.6)]`} 
                style={{ height: `${height}%`, opacity: (height / 100) * 0.6 + 0.4 }}></div>
            ))}
           </div>

           <div className="mt-20 text-center">
              <p className="text-[12px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">FIKO EST EN LIGNE</p>
              <div className="flex justify-center gap-12 mt-10">
                <div className="text-center">
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-2">ENGAGEMENT</p>
                  <p className="text-3xl font-black text-white">{leadScore}%</p>
                </div>
                <div className="text-center">
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-2">MODE</p>
                  <p className="text-3xl font-black text-[#E10600]">CLOSING</p>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* Shared UI elements */}
      <div className="absolute bottom-12 right-12 flex gap-8 z-50">
         <button onClick={handleClose} className="size-20 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white/10 transition-all text-slate-400 group">
           <X size={48} className="group-hover:rotate-90 transition-transform" />
         </button>
      </div>

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-6 text-white text-xs font-black uppercase tracking-widest flex items-center gap-6 shadow-2xl">
           <AlertTriangle size={24} /> {error}
           <button onClick={() => { setError(null); startVocalSession(); }} className="underline">Réessayer</button>
        </div>
      )}
    </div>
  );
};

