function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

enum FikoStep {
  PRE_START = 'pre_start',
  KEYWORD = 'keyword',
  CONVERSATION = 'conversation'
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [step, setStep] = useState<FikoStep>(FikoStep.PRE_START);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(50).fill(5));
  const [leadScore, setLeadScore] = useState(0);
  const [statusText, setStatusText] = useState("");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => stopSession();
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStep(FikoStep.KEYWORD);

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              // Vibration logic based on actual audio input
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              const multi = step === FikoStep.KEYWORD ? 5 : 100;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * multi)) + 5));

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // Trigger "OK FIKO"
            if (step === FikoStep.KEYWORD && message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text.toLowerCase();
              if (text.includes("fiko") || text.includes("ok")) {
                setStep(FikoStep.CONVERSATION);
                setStatusText("FIKO EN LIGNE");
                sessionRef.current?.sendRealtimeInput({ text: "URGENT: L'utilisateur vient de dire OK FIKO. Démarre IMMÉDIATEMENT ton script d'introduction brutale : 'Très bien. Je suis FIKO. Avant de vous expliquer quoi que ce soit… je vais vous poser une seule question. Est-ce que votre site vous apporte des clients régulièrement ?'" });
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(50).fill(5));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 3, 100));
            }
          },
          onerror: (e) => {
            console.error('Fiko Error:', e);
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setError("Accès micro refusé. FIKO ne peut pas vous entendre.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(() => {});
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
    }

    setBars(new Array(50).fill(5));
    isClosingRef.current = false;
  };

  const handleClose = () => {
    console.log("La conversation s’arrête ici. Vos concurrents, eux, continuent.");
    onClose();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden select-none">
      <div className="absolute inset-0 hex-bg opacity-[0.03]"></div>

      {/* Brutal Entrance */}
      {step === FikoStep.PRE_START && (
        <div className="max-w-3xl w-full text-center space-y-16 animate-in fade-in zoom-in-95 duration-1000 relative z-10">
          <div className="space-y-6">
            <h2 className="text-4xl lg:text-7xl font-black uppercase tracking-tighter leading-none text-white">
              Vous êtes sur le point <br/>de parler à <span className="text-[#E10600]">FIKO.</span>
            </h2>
            <p className="text-xl lg:text-2xl text-slate-500 font-light uppercase tracking-[0.3em]">
              Directeur Commercial Virtuel de Krypton AI.
            </p>
          </div>

          <div className="p-12 border-l-4 border-[#E10600] bg-white/[0.02] text-left max-w-2xl mx-auto">
             <p className="text-xl text-slate-400 font-light italic leading-relaxed uppercase tracking-widest">
                "Cette conversation peut remettre en question votre manière de vendre."
             </p>
          </div>

          <button 
            onClick={startVocalSession}
            disabled={isConnecting}
            className="group relative bg-[#E10600] text-white px-20 py-10 rounded-sm font-black text-xs transition-all uppercase tracking-[0.6em] shadow-[0_0_80px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto"
          >
            {isConnecting ? <Loader2 className="animate-spin" size={24} /> : <>🎙️ Démarrer avec FIKO <ArrowRight size={24} className="group-hover:translate-x-3 transition-transform" /></>}
          </button>
        </div>
      )}

      {/* Waiting for Keyword */}
      {step === FikoStep.KEYWORD && (
        <div className="flex flex-col items-center gap-24 animate-in zoom-in-95 duration-1000 text-center">
          <div className="relative group">
             <div className="absolute inset-0 bg-[#E10600]/10 blur-[120px] rounded-full group-hover:bg-[#E10600]/30 transition-all duration-1000"></div>
             <Mic className="text-[#E10600] relative z-10 size-48 opacity-60 animate-pulse" strokeWidth={1} />
          </div>
          <div className="space-y-10">
            <h3 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter text-white animate-in slide-in-from-bottom-8 duration-700">
              Dites <span className="text-[#E10600] italic">“OK FIKO”</span>
            </h3>
            <p className="text-[10px] font-black uppercase tracking-[0.8em] text-slate-700">
              LE SYSTÈME ATTEND VOTRE SIGNAL POUR L'ACTIVATION NEURALE
            </p>
          </div>
          <div className="flex gap-2 h-12 items-center">
            {bars.map((h, i) => (
              <div key={i} className="w-1.5 h-full bg-white/5 rounded-full overflow-hidden">
                <div className="w-full bg-[#E10600] transition-all duration-300 opacity-40" style={{ height: `${h}%` }}></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Active Conversation (The Shock) */}
      {step === FikoStep.CONVERSATION && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-7xl relative animate-in fade-in duration-2000">
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-10 pointer-events-none">
              <Hexagon size={900} className="text-[#E10600] animate-[spin_120s_linear_infinite]" strokeWidth={0.1} />
              <Hexagon size={600} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[#E10600] animate-[spin_80s_linear_infinite_reverse]" strokeWidth={0.2} />
           </div>

           <div className="relative z-10 flex items-center justify-center gap-4 h-96 w-full">
            {bars.map((height, i) => (
              <div key={i} className="w-3 md:w-4 rounded-full transition-all duration-150 bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_30px_rgba(225,6,0,0.4)]" 
                style={{ height: `${height}%`, opacity: (height / 100) * 0.5 + 0.5 }}></div>
            ))}
           </div>

           <div className="mt-32 text-center space-y-16">
              <div className="space-y-4">
                <p className="text-[12px] font-black uppercase tracking-[0.8em] text-[#E10600] animate-pulse">FIKO EST EN LIGNE</p>
                <h4 className="text-xl font-black uppercase tracking-widest text-white/40">ANALYSE STRATÉGIQUE EN COURS</h4>
              </div>

              <div className="flex justify-center gap-24">
                <div className="text-center group">
                  <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-4 group-hover:text-[#E10600] transition-colors">INTENTION CLIENT</p>
                  <p className="text-5xl font-black text-white">{leadScore}%</p>
                </div>
                <div className="text-center group">
                  <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-4 group-hover:text-[#E10600] transition-colors">MODE OPÉRATOIRE</p>
                  <p className="text-5xl font-black text-[#E10600]">CLOSING</p>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* Exit & Controls */}
      <div className="absolute bottom-16 flex items-center gap-12 z-50">
         <div className="flex items-center gap-4 px-8 py-3 bg-white/5 border border-white/10 rounded-full backdrop-blur-3xl opacity-20 hover:opacity-100 transition-opacity">
            <div className="size-2 bg-emerald-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Canal Sécurisé AES-512</span>
         </div>
         <button 
           onClick={handleClose} 
           className="group size-24 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-[#E10600] hover:border-[#E10600] transition-all text-slate-400 hover:text-white"
           title="Mettre fin à l'épreuve"
         >
           <X size={40} className="group-hover:rotate-90 transition-transform" />
         </button>
      </div>

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-10 text-white text-xs font-black uppercase tracking-[0.4em] flex items-center gap-8 shadow-2xl animate-in slide-in-from-top-4">
           <AlertTriangle size={32} /> 
           <div className="space-y-2">
             <p>{error}</p>
             <button onClick={() => { setError(null); startVocalSession(); }} className="underline block opacity-70 hover:opacity-100">Réinitialiser la liaison</button>
           </div>
        </div>
      )}
    </div>
  );
};

