function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoicePage: React.FC = () => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(30).fill(5));
  const [statusText, setStatusText] = useState("SYSTÈME PRÊT AU DÉPLOIEMENT");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const retryCountRef = useRef(0);
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => stopSession();
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStatusText("SYNCHRONISATION NEURALE...");

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // CRITICAL: Force resume to avoid "suspended" state issues
      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatusText("LIAISON NEURALE ÉTABLIE");
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              setBars(prev => prev.map(() => Math.floor(Math.random() * 90) + 10));
              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(30).fill(10));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Krypton Link Error:', e);
            if (retryCountRef.current < 2 && !isClosingRef.current) {
              retryCountRef.current++;
              setStatusText("RECONNEXION...");
              setTimeout(startSession, 2000);
            } else {
              setError("Échec de la liaison neurale. Permission système ou service indisponible.");
              stopSession();
            }
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: `
            You are a senior strategic sales consultant at Krypton AI. 
            Tone: Peer-to-peer, authoritative, calm, and visionary.
            Focus on closing and strategic diagnostic.
          `
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("Accès audio refusé par le système. Vérifiez vos permissions navigateur.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(err => console.warn('AudioContext close error:', err));
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    setBars(new Array(30).fill(5));
    nextStartTimeRef.current = 0;
    setStatusText("SYSTÈME PRÊT AU DÉPLOIEMENT");
    isClosingRef.current = false;
  };

  return (
    <div className="relative h-[calc(100vh-80px)] overflow-hidden bg-[#0B0B0F] flex flex-col items-center justify-center">
      <div className="absolute inset-0 bg-gradient-to-b from-[#E10600]/5 to-transparent pointer-events-none"></div>
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#E10600]/20 to-transparent"></div>

      <div className="absolute top-20 flex flex-col items-center gap-6 z-20">
        <div className="flex items-center gap-4 px-6 py-2 bg-[#1A1A1F]/80 border border-white/5 rounded-full backdrop-blur-2xl shadow-2xl">
          <div className="relative flex size-2">
            <div className={`absolute inset-0 rounded-full ${isActive ? 'bg-[#E10600] animate-ping' : 'bg-slate-700'}`}></div>
            <div className={`relative size-2 rounded-full ${isActive ? 'bg-[#E10600]' : 'bg-slate-600'}`}></div>
          </div>
          <span className={`text-[10px] font-black tracking-[0.4em] uppercase transition-all ${isActive ? 'text-[#E10600]' : 'text-slate-500'}`}>
            {statusText}
          </span>
        </div>
      </div>

      <div className="relative w-full max-w-5xl flex items-center justify-center h-[500px]">
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none overflow-hidden">
          <div className={`transition-all duration-1000 ${isActive ? 'scale-110 opacity-100' : 'scale-75 opacity-20'}`}>
            <Hexagon size={600} className="text-[#E10600]/5 animate-[spin_60s_linear_infinite]" strokeWidth={0.5} />
            <Hexagon size={450} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[#E10600]/10 animate-[spin_40s_linear_infinite_reverse]" strokeWidth={1} />
          </div>
        </div>

        <div className="relative z-10 flex items-end gap-2 h-48">
          {bars.map((height, i) => (
            <div 
              key={i} 
              className={`w-1.5 md:w-2.5 rounded-full transition-all duration-150 ${isActive ? 'bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_15px_rgba(225,6,0,0.4)]' : 'bg-slate-800'}`} 
              style={{ 
                height: `${height}%`,
                opacity: isActive ? (height / 100) * 0.7 + 0.3 : 0.2
              }}
            ></div>
          ))}
        </div>
      </div>

      <div className="absolute bottom-20 flex justify-center w-full">
        <div className="bg-[#1A1A1F]/40 backdrop-blur-3xl border border-white/5 p-4 rounded-full flex items-center gap-4 shadow-2xl group">
          <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white transition-all hover:bg-white/5 rounded-full">
            <Settings size={20} />
          </button>

          <button 
            disabled={isConnecting}
