            }`}
          >
            {isConnecting ? <Loader2 className="size-10 animate-spin" /> : isActive ? <PhoneOff size={32} /> : <Mic size={32} />}
            {isActive && <div className="absolute -inset-4 border border-[#E10600]/20 rounded-full animate-ping pointer-events-none"></div>}
          </button>

          <button className="size-16 flex items-center justify-center text-slate-600 hover:text-white transition-all hover:bg-white/5 rounded-full">
            <Volume2 size={20} />
          </button>
        </div>
      </div>

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] animate-in slide-in-from-top-4 duration-500">
          <div className="bg-[#E10600] border border-white/20 p-5 rounded-sm flex items-center gap-5 shadow-2xl">
            <AlertTriangle className="text-white" size={24} />
            <div className="flex flex-col gap-2">
              <p className="text-[10px] font-black uppercase tracking-widest text-white">{error}</p>
              <button onClick={() => { setError(null); startSession(); }} className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-white/60 underline">
