          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              // Vibration logic based on actual amplitude
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              const multi = step === FikoStep.KEYWORD ? 40 : 250;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * multi)) + 5));

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // ATOMIC ACTIVATION (Detecting OK FIKO)
            if (wakeupDetectionActive.current && (message.serverContent?.inputTranscription || message.serverContent?.modelTurn)) {
              const text = (message.serverContent?.inputTranscription?.text || "").toLowerCase();
              if (text.length > 0) setTranscription(text);

              // Keywords variations for robustness
              const wakeKeywords = ["fiko", "ok", "hey", "fico", "allo", "okay"];
              if (wakeKeywords.some(k => text.includes(k))) {
                wakeupDetectionActive.current = false;
                setStep(FikoStep.CONVERSATION);

                // FORCE THE MODEL TURN IMMEDIATELY
                sessionRef.current?.sendRealtimeInput({ 
                  media: {
                    data: encode(new TextEncoder().encode("L'UTILISATEUR A DIT 'OK FIKO'. RÉPONDS MAINTENANT AVEC TON SCRIPT : 'Très bien. Je suis FIKO. Avant de vous expliquer quoi que ce soit… je vais vous poser une seule question. Est-ce que votre site vous apporte des clients régulièrement ?'")),
                    mimeType: 'text/plain'
                  }
                });
              }
            }

            // AUDIO OUTPUT ENGINE
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(60).fill(8));
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 5, 100));
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Liaison FIKO Fail:', e);
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("ERREUR D'ACTIVATION : Permission micro ou AudioContext bloqué par le système.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(() => {});
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    setBars(new Array(60).fill(5));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  };

  // ADDED: handleClose function to stop session and notify parent
  const handleClose = () => {
    stopSession();
    onClose();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      {/* 1. Pre-Start */}
      {step === FikoStep.PRE_START && (
        <div className="max-w-2xl w-full text-center space-y-16 animate-in zoom-in-95 duration-700 relative z-10">
          <div className="space-y-4">
             <div className="inline-block px-4 py-1 border border-[#E10600] text-[#E10600] text-[10px] font-black uppercase tracking-[0.6em] mb-8">
               ACTIVATION NEURALE
             </div>
             <h2 className="text-5xl lg:text-8xl font-black uppercase tracking-tighter leading-[0.8] text-white">
               Face-à-face <br/>avec <span className="text-[#E10600]">FIKO.</span>
             </h2>
          </div>

          <div className="p-12 border-l-2 border-[#E10600] bg-white/[0.02] text-left max-w-xl mx-auto italic text-slate-400 text-xl font-light uppercase tracking-widest leading-relaxed">
             "Veuillez autoriser l'accès micro. FIKO est prêt à vous écouter."
          </div>

          <button 
            onClick={startVocalSession}
            disabled={isConnecting}
            className="group relative bg-[#E10600] text-white px-16 py-8 rounded-sm font-black text-xs transition-all uppercase tracking-[0.5em] shadow-[0_0_100px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto"
          >
            {isConnecting ? <Loader2 className="animate-spin" size={24} /> : <>🎙️ Démarrer la Liaison <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" /></>}
          </button>
        </div>
      )}

      {/* 2. Keyword Search */}
      {step === FikoStep.KEYWORD && (
        <div className="flex flex-col items-center gap-24 text-center animate-in zoom-in-95 duration-1000">
          <div className="relative group">
             <div className="absolute inset-0 bg-[#E10600]/10 blur-[150px] rounded-full group-hover:bg-[#E10600]/30 transition-all duration-1000"></div>
             <div className="relative z-10 p-20 border border-white/5 bg-white/[0.02] rounded-full animate-pulse shadow-[0_0_50px_rgba(225,6,0,0.1)]">
                <Mic className="text-[#E10600] size-48" strokeWidth={0.5} />
             </div>
          </div>
          <div className="space-y-8">
            <h3 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter text-white">
              Dites <span className="text-[#E10600] italic">“OK FIKO”</span>
            </h3>
            <p className="text-[11px] font-black uppercase tracking-[0.8em] text-slate-700 animate-pulse">
