            if (isClosingRef.current) return;

            // DÉTECTION "OK FIKO" ULTRA-RAPIDE
            const text = (message.serverContent?.inputTranscription?.text || "").toLowerCase();
            if (text.length > 0) setTranscription(text);

            if (wakeupDetectionActive.current) {
               // Si le modèle commence à parler OU si on détecte le mot-clé
               const hasKeyword = text.includes("fiko") || text.includes("ok") || text.includes("fico") || text.includes("allo");
               const modelStarted = !!message.serverContent?.modelTurn;

               if (hasKeyword || modelStarted) {
                  wakeupDetectionActive.current = false;
                  setStep(FikoStep.CONVERSATION);

                  // Forcer le déclenchement immédiat du script si ce n'est pas déjà fait
