import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { X, Mic, PhoneOff, Activity, Hexagon, Loader2, ArrowRight, AlertTriangle, RefreshCcw } from 'lucide-react';
import { Agent } from '../types';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Fix: Ensure byteLength is even for Int16Array and use buffer offset
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

enum FikoStep {
  PRE_START = 'pre_start',
  KEYWORD = 'keyword',
  CONVERSATION = 'conversation'
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [step, setStep] = useState<FikoStep>(FikoStep.PRE_START);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(60).fill(5));
  const [leadScore, setLeadScore] = useState(0);
  const [transcription, setTranscription] = useState("");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);
  const wakeupDetectionActive = useRef(false);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);

    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(() => {});
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    setBars(new Array(60).fill(5));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  }, []);

  useEffect(() => {
    return () => stopSession();
  }, [stopSession]);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStep(FikoStep.KEYWORD);
    wakeupDetectionActive.current = true;

    try {
      // 1. ATOMIC AUDIO WAKEUP
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Ensure running state immediately
      await inputCtx.resume();
      await outputCtx.resume();

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              // Dynamic Visualizer Logic
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              const multi = wakeupDetectionActive.current ? 60 : 300;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * multi)) + 5));

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            // 2. ULTRA-FAST PHONETIC DETECTION
            const text = (message.serverContent?.inputTranscription?.text || "").toLowerCase();
            if (text.length > 0) setTranscription(text);

            if (wakeupDetectionActive.current) {
              // Fuzzy wake word detection (local + model signals)
              const wakeWords = ["fiko", "ok", "hey", "fico", "allo", "okay", "ici", "bonjour"];
              const keywordDetected = wakeWords.some(w => text.includes(w));
              const modelTurnDetected = !!message.serverContent?.modelTurn;

              if (keywordDetected || modelTurnDetected) {
                wakeupDetectionActive.current = false;
                setStep(FikoStep.CONVERSATION);

                // INJECT ABSOLUTE PRIORITY COMMAND
                sessionRef.current?.sendRealtimeInput([{ 
                  text: "L'utilisateur a activé FIKO. Exécute immédiatement ton script d'introduction : 'Très bien. Je suis FIKO...'" 
                }]);
              }
            }

            // High Fidelity Audio Engine
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);

              try {
                const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);
                source.addEventListener('ended', () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0 && !wakeupDetectionActive.current) {
                    setBars(new Array(60).fill(10));
                  }
                });
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                setLeadScore(prev => Math.min(prev + 5, 100));
              } catch (audioErr) {
                console.error("Audio Processing Error:", audioErr);
              }
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Liaison FIKO Fail:', e);
            // Handle service unavailable with a friendly error
            if (e.toString().includes("unavailable")) {
              setError("LE RÉSEAU NEURAL EST SATURÉ (SERVICE UNAVAILABLE). TENTEZ UNE RÉINITIALISATION.");
            } else {
              setError("RUPTURE DE LA LIAISON : ACCÈS MICRO OU RÉSEAU COMPROMIS.");
            }
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error("Critical Session Init Error:", err);
      setError("ERREUR D'INITIALISATION : LE SYSTÈME EST ACTUELLEMENT HORS-LIGNE OU SATURÉ.");
      setIsConnecting(false);
    }
  };

  const handleClose = () => {
    stopSession();
    onClose();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      {/* 1. Pre-Start */}
      {step === FikoStep.PRE_START && (
        <div className="max-w-2xl w-full text-center space-y-16 animate-in zoom-in-95 duration-700 relative z-10">
          <div className="space-y-4">
             <div className="inline-block px-4 py-1 border border-[#E10600] text-[#E10600] text-[10px] font-black uppercase tracking-[0.6em] mb-8">
               SESSION STRATÉGIQUE HAUTE FRÉQUENCE
             </div>
             <h2 className="text-5xl lg:text-8xl font-black uppercase tracking-tighter leading-[0.8] text-white">
               Face-à-face <br/>avec <span className="text-[#E10600]">FIKO.</span>
             </h2>
          </div>

          <div className="p-12 border-l-2 border-[#E10600] bg-white/[0.02] text-left max-w-xl mx-auto italic text-slate-400 text-xl font-light uppercase tracking-widest leading-relaxed">
             "Activez la liaison pour soumettre votre vision au diagnostic de FIKO."
          </div>

          <button 
            onClick={startVocalSession}
            disabled={isConnecting}
            className="group relative bg-[#E10600] text-white px-16 py-8 rounded-sm font-black text-xs transition-all uppercase tracking-[0.5em] shadow-[0_0_100px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto"
          >
            {isConnecting ? <Loader2 className="animate-spin" size={24} /> : <>🎙️ Initialiser FIKO <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" /></>}
          </button>
        </div>
      )}

      {/* 2. Keyword Search */}
      {step === FikoStep.KEYWORD && (
        <div className="flex flex-col items-center gap-24 text-center animate-in zoom-in-95 duration-1000">
          <div className="relative group">
             <div className="absolute inset-0 bg-[#E10600]/10 blur-[150px] rounded-full group-hover:bg-[#E10600]/30 transition-all duration-1000"></div>
             <div className="relative z-10 p-20 border border-white/5 bg-white/[0.02] rounded-full animate-pulse shadow-[0_0_50px_rgba(225,6,0,0.1)]">
                <Mic className="text-[#E10600] size-48" strokeWidth={0.5} />
             </div>
          </div>
          <div className="space-y-8">
            <h3 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter text-white">
              Dites <span className="text-[#E10600] italic">“OK FIKO”</span>
            </h3>
            <p className="text-[11px] font-black uppercase tracking-[0.8em] text-slate-700 animate-pulse">
              EN ATTENTE DU SIGNAL D'ACTIVATION...
            </p>
          </div>
          {transcription && (
            <div className="bg-white/5 border border-white/10 px-6 py-2 rounded-full text-slate-300 font-mono text-[10px] uppercase tracking-widest animate-in fade-in max-w-sm truncate">
              ANALYSE : "{transcription}"
            </div>
          )}
          <div className="flex gap-2 h-16 items-center">
            {bars.map((h, i) => (
              <div key={i} className="w-1.5 h-full bg-white/5 rounded-full overflow-hidden">
                <div className="w-full bg-[#E10600] transition-all duration-300" style={{ height: `${h}%`, opacity: 0.6 }}></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 3. The Conversation */}
      {step === FikoStep.CONVERSATION && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-7xl relative animate-in fade-in duration-2000">
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-20 pointer-events-none">
              <Hexagon size={1000} className="text-[#E10600]/10 animate-[spin_180s_linear_infinite]" strokeWidth={0.1} />
              <Hexagon size={700} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[#E10600]/20 animate-[spin_100s_linear_infinite_reverse]" strokeWidth={0.2} />
           </div>

           <div className="relative z-10 flex items-center justify-center gap-3 h-96 w-full">
            {bars.map((height, i) => (
              <div key={i} className="w-3 md:w-5 rounded-full transition-all duration-150 bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_40px_rgba(225,6,0,0.5)]" 
                style={{ height: `${height}%`, opacity: (height / 100) * 0.4 + 0.6 }}></div>
            ))}
           </div>

           <div className="mt-32 text-center space-y-20">
              <div className="space-y-4">
                <div className="flex items-center justify-center gap-4 text-[#E10600] text-[12px] font-black uppercase tracking-[1em] animate-pulse">
                  <div className="size-2 bg-[#E10600] rounded-full shadow-[0_0_10px_#E10600]"></div> FIKO EN LIGNE
                </div>
                <h4 className="text-2xl font-black uppercase tracking-[0.4em] text-white/40 italic">CONVERSATION STRATÉGIQUE</h4>
              </div>

              <div className="flex justify-center gap-32">
                <div className="text-center group border-l border-white/5 pl-12 transition-all">
                  <p className="text-[11px] font-black text-slate-700 uppercase tracking-widest mb-4">MATURITÉ DU LEAD</p>
                  <p className="text-6xl font-black text-white">{leadScore}%</p>
                </div>
                <div className="text-center group border-l border-white/5 pl-12 transition-all">
                  <p className="text-[11px] font-black text-slate-700 uppercase tracking-widest mb-4">STATUS</p>
                  <p className="text-6xl font-black text-[#E10600]">CLOSING</p>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* Exit & Control */}
      <div className="absolute bottom-16 flex items-center gap-12 z-50">
         <button 
           onClick={handleClose} 
           className="group size-24 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all text-slate-500 shadow-2xl"
           title="Fermer la liaison"
         >
           <X size={48} className="group-hover:rotate-90 transition-transform" />
         </button>
      </div>

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-10 text-white text-xs font-black uppercase tracking-[0.5em] flex items-center gap-10 shadow-[0_0_100px_#E10600] animate-in slide-in-from-top-4">
           <AlertTriangle size={40} className="flex-shrink-0" /> 
           <div className="space-y-4">
             <p className="text-lg font-bold leading-tight uppercase">{error}</p>
             <button 
               onClick={() => { setError(null); startVocalSession(); }} 
               className="flex items-center gap-4 underline opacity-80 hover:opacity-100 uppercase tracking-widest text-[10px] font-black"
             >
               <RefreshCcw size={14} /> Tenter une réinitialisation nucléaire
             </button>
           </div>
        </div>
      )}
    </div>
  );
