import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { X, Send, Bot, User, Loader2, ShieldCheck, Sparkles, Hexagon } from 'lucide-react';
import { Agent, Message } from '../types';

interface AIChatOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

const AIChatOverlay: React.FC<AIChatOverlayProps> = ({ agent, onClose }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (agent && messages.length === 0) {
      setMessages([{ 
        role: 'model', 
        text: `Très bien. Je suis FIKO™, le Directeur Commercial Virtuel de Krypton AI. Avant qu'on ne parle de solutions, j'aimerais comprendre : quel est le plus gros goulot d'étranglement qui freine votre croissance aujourd'hui ?` 
      }]);
    }
  }, [agent]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || !agent) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: agent.systemPrompt,
          thinkingConfig: { thinkingBudget: 15000 },
          temperature: 0.7,
          topP: 0.9,
        }
      });

      const aiText = response.text || "Je n'ai pas pu finaliser l'analyse stratégique. Pouvez-vous reformuler ?";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Le noyau neural de FIKO™ subit une forte charge cognitive. Une seconde..." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[60] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-0 md:p-10 animate-in fade-in duration-500">
      <div className="bg-[#0B0B0F] border border-white/10 w-full max-w-4xl h-full md:h-[90vh] flex flex-col rounded-sm shadow-[0_0_150px_rgba(225,6,0,0.2)] overflow-hidden relative">
        <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

        {/* Header */}
        <div className="bg-[#1A1A1F] p-8 border-b border-white/10 flex justify-between items-center relative z-10">
          <div className="flex items-center gap-6">
            <div className="relative">
              <div className="size-16 bg-[#E10600]/10 border border-[#E10600]/30 flex items-center justify-center rounded-sm">
                 <Bot className="text-[#E10600]" size={32} />
              </div>
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-4 border-[#1A1A1F] animate-pulse shadow-[0_0_10px_#10b981]"></div>
            </div>
            <div>
              <div className="flex items-center gap-3">
                 <h3 className="font-black uppercase tracking-[0.2em] text-lg">{agent.name}</h3>
                 <span className="bg-[#E10600] text-white text-[9px] font-black px-2 py-0.5 uppercase tracking-widest rounded-sm">FIKO™_CORE</span>
              </div>
              <p className="text-[10px] text-slate-500 uppercase tracking-[0.3em] font-bold mt-1 flex items-center gap-2">
                <ShieldCheck size={12} className="text-emerald-500" /> CONFIANCE NEURALE ACTIVE
              </p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="size-12 flex items-center justify-center text-slate-500 hover:text-white transition-all hover:bg-white/5 rounded-full"
          >
            <X size={32} />
          </button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-grow overflow-y-auto p-10 space-y-16 scroll-smooth relative z-10">
          {messages.map((m, i) => (
            <div key={i} className={`flex gap-8 ${m.role === 'model' ? 'flex-row' : 'flex-row-reverse animate-in slide-in-from-right-4 duration-300'}`}>
              <div className={`size-12 flex-shrink-0 flex items-center justify-center rounded-sm transition-all shadow-xl ${m.role === 'model' ? 'bg-[#E10600] text-white' : 'bg-white text-black'}`}>
                {m.role === 'model' ? <Bot size={24} /> : <User size={24} />}
              </div>
              <div className={`max-w-[80%] p-10 rounded-sm text-lg leading-relaxed relative ${
                m.role === 'model' 
                ? 'bg-[#1A1A1F] border border-white/5 text-slate-200 font-light' 
                : 'bg-white/5 border border-white/10 text-white italic font-medium backdrop-blur-md'
              }`}>
                {m.text.split('\n').map((line, idx) => (
                  <p key={idx} className={idx > 0 ? 'mt-4' : ''}>{line}</p>
                ))}
                {m.role === 'model' && (
                  <div className="absolute top-0 left-0 w-2 h-full bg-[#E10600] opacity-50"></div>
                )}
                {m.role === 'model' && (
                  <div className="absolute top-4 right-4 opacity-5">
                    <Hexagon size={60} />
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex gap-8 animate-pulse">
              <div className="size-12 bg-[#E10600] text-white flex items-center justify-center rounded-sm shadow-[0_0_20px_#E10600]">
                <Sparkles size={24} className="animate-spin duration-[3s]" />
              </div>
              <div className="bg-[#1A1A1F] border border-white/5 p-10 rounded-sm flex flex-col gap-4 max-w-[80%]">
                <p className="text-[10px] font-black uppercase tracking-[0.4em] text-[#E10600] mb-2">FIKO™ analyse votre vision...</p>
                <div className="flex gap-2">
                  <div className="w-2 h-2 bg-[#E10600] rounded-full animate-bounce [animation-delay:0s]"></div>
                  <div className="w-2 h-2 bg-[#E10600] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-2 h-2 bg-[#E10600] rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Input area */}
        <div className="p-10 border-t border-white/10 bg-[#0B0B0F]/80 backdrop-blur-xl relative z-10">
          <div className="max-w-4xl mx-auto relative group">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="DITES À FIKO™ CE QUE VOUS VOULEZ RÉALISER"
              className="w-full bg-black border border-white/10 p-8 pr-28 text-sm font-black uppercase tracking-[0.4em] text-white focus:border-[#E10600] outline-none transition-all placeholder:text-slate-800 shadow-2xl"
              autoFocus
            />
            <button 
              onClick={handleSend}
              disabled={isTyping || !input.trim()}
              className="absolute right-6 top-1/2 -translate-y-1/2 bg-[#E10600] p-5 text-white hover:bg-red-700 transition-all rounded-sm shadow-xl shadow-red-500/30 disabled:opacity-50 disabled:cursor-not-allowed group"
            >
              <Send size={24} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
            </button>
          </div>
          <div className="flex justify-between items-center mt-6 px-4">
             <div className="text-[9px] text-slate-700 uppercase tracking-[0.5em] font-black flex items-center gap-1">
                KRYPTON AI BY
                <a 
                    href="https://www.koffmann.group" 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    className="animated-koffmann-text font-black normal-case tracking-normal px-1 text-[11px] hover:scale-105 transition-transform"
                >
                    Koffmann Group
                </a>
             </div>
             <p className="text-[9px] text-slate-700 uppercase tracking-[0.5em] font-black">
                SÉCURISÉ PAR FIKO™ MEMORY CORE
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIChatOverlay;

