function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
}

enum FikoStep {
  PRE_START = 'pre_start',
  CONNECTING = 'connecting',
  ACTIVE = 'active'
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose }) => {
  const [step, setStep] = useState<FikoStep>(FikoStep.PRE_START);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(60).fill(5));
  const [leadScore, setLeadScore] = useState(0);
  const [transcription, setTranscription] = useState("");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);
  const watchdogRef = useRef<number | null>(null);
  const retryCountRef = useRef(0);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);

    if (watchdogRef.current) window.clearTimeout(watchdogRef.current);

    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();

    const closeContext = (ctx: AudioContext | null) => {
      if (ctx && ctx.state !== 'closed') {
        ctx.close().catch(() => {});
      }
    };

    closeContext(inputAudioContextRef.current);
    closeContext(outputAudioContextRef.current);
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    setBars(new Array(60).fill(5));
    nextStartTimeRef.current = 0;
    isClosingRef.current = false;
  }, []);

  useEffect(() => {
    return () => stopSession();
  }, [stopSession]);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startVocalSession = async () => {
    if (isClosingRef.current) return;
    setStep(FikoStep.CONNECTING);
    setError(null);

    try {
      // 1. FORCED MIC ACTIVATION
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      await inputCtx.resume();
      await outputCtx.resume();

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setStep(FikoStep.ACTIVE);
            setIsActive(true);
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);

              // Visual feedback
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 400)) + 5));

              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // 2. WATCHDOG ANTI-SILENCE : If no turn from model after 1.5s, force intro
            watchdogRef.current = window.setTimeout(() => {
              if (sourcesRef.current.size === 0) {
                sessionPromise.then(s => s.sendRealtimeInput([{ text: "L'utilisateur est là. Lance ton script d'introduction immédiatement." }]));
              }
            }, 1500);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            const interimText = message.serverContent?.inputTranscription?.text?.toLowerCase() || "";
            if (interimText) setTranscription(interimText);

            // Cancel watchdog if model starts talking
            if (message.serverContent?.modelTurn && watchdogRef.current) {
              window.clearTimeout(watchdogRef.current);
              watchdogRef.current = null;
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              try {
                const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);
                source.addEventListener('ended', () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) setBars(new Array(60).fill(10));
                });
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                setLeadScore(prev => Math.min(prev + 5, 100));
              } catch (audioErr) { console.error("Audio Engine Error:", audioErr); }
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Liaison FIKO™ Fail:', e);
            const errorMsg = e.toString().toLowerCase();

            // Handle service unavailable with automatic retry or clear UI
            if (errorMsg.includes("unavailable") && retryCountRef.current < 2) {
                retryCountRef.current++;
                stopSession();
                setTimeout(startVocalSession, 2000);
            } else {
              setError("LE RÉSEAU NEURAL EST ACTUELLEMENT SATURÉ OU LE MICRO EST BLOQUÉ.");
              setStep(FikoStep.PRE_START);
              stopSession();
            }
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error("Critical Session Error:", err);
      setError("ÉCHEC DE CONNEXION. SERVICE KRYPTON INDISPONIBLE.");
      setStep(FikoStep.PRE_START);
    }
  };

  const handleClose = () => {
    stopSession();
    onClose();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      {/* Background Decorative Hex */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-20 pointer-events-none">
        <Hexagon size={1000} className="text-[#E10600]/10 animate-[spin_180s_linear_infinite]" strokeWidth={0.1} />
        <Hexagon size={700} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[#E10600]/20 animate-[spin_100s_linear_infinite_reverse]" strokeWidth={0.2} />
      </div>

      {step === FikoStep.PRE_START && (
        <div className="max-w-2xl w-full text-center space-y-16 animate-in zoom-in-95 duration-700 relative z-10">
          <div className="space-y-4">
             <div className="inline-block px-4 py-1 border border-[#E10600] text-[#E10600] text-[10px] font-black uppercase tracking-[0.6em] mb-8">
               SESSION STRATÉGIQUE HAUTE FRÉQUENCE
             </div>
             <h2 className="text-5xl lg:text-8xl font-black uppercase tracking-tighter leading-[0.8] text-white">
               Face-à-face <br/>avec <span className="text-[#E10600]">FIKO™.</span>
             </h2>
          </div>

          <div className="p-12 border-l-2 border-[#E10600] bg-white/[0.02] text-left max-w-xl mx-auto italic text-white text-xl lg:text-2xl font-light uppercase tracking-widest leading-relaxed">
             "Activez la liaison pour soumettre votre vision au diagnostic de FIKO™."
          </div>

          <button 
            onClick={startVocalSession}
            className="group relative bg-[#E10600] text-white px-16 py-8 rounded-sm font-black text-xs transition-all uppercase tracking-[0.5em] shadow-[0_0_100px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto"
          >
            🎙️ Initialiser FIKO™ <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
          </button>
        </div>
      )}

      {step === FikoStep.CONNECTING && (
        <div className="flex flex-col items-center gap-16 animate-in fade-in duration-500">
           <div className="relative">
              <Loader2 className="size-32 text-[#E10600] animate-spin" strokeWidth={1} />
              <div className="absolute inset-0 flex items-center justify-center">
                 <Zap className="text-white animate-pulse" size={32} />
              </div>
           </div>
           <p className="text-[12px] font-black uppercase tracking-[0.8em] text-[#E10600] animate-pulse text-center">
             ÉTABLISSEMENT DU CANAL DE CONFIANCE...
           </p>
        </div>
      )}

      {step === FikoStep.ACTIVE && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-7xl relative animate-in fade-in duration-1000">
           {/* Dynamic Waveform Visualizer */}
           <div className="relative z-10 flex items-center justify-center gap-2 h-96 w-full px-4">
            {bars.map((height, i) => (
              <div key={i} className="w-2 md:w-3 lg:w-4 rounded-full transition-all duration-150 bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_40px_rgba(225,6,0,0.4)]" 
                style={{ height: `${height}%`, opacity: (height / 100) * 0.4 + 0.6 }}></div>
            ))}
           </div>

           <div className="mt-24 text-center space-y-20 relative z-20">
              <div className="space-y-8">
                <div className="flex items-center justify-center gap-4 text-[#E10600] text-[14px] font-black uppercase tracking-[1em] animate-pulse">
                  <div className="size-2.5 bg-[#E10600] rounded-full shadow-[0_0_20px_#E10600]"></div> FIKO™ EN LIGNE
                </div>
                {transcription && (
                   <div className="max-w-xl mx-auto px-8 py-3 bg-white/10 border border-white/20 rounded-sm text-white font-mono text-sm uppercase tracking-widest animate-in fade-in shadow-2xl">
                     "{transcription}"
                   </div>
                )}
              </div>

              <div className="flex justify-center gap-20 lg:gap-40">
                <div className="text-center group border-l-2 border-[#E10600]/30 pl-12 transition-all">
                  <p className="text-[12px] font-black text-slate-500 uppercase tracking-widest mb-4">LEAD SCORE</p>
                  <p className="text-7xl lg:text-8xl font-black text-white drop-shadow-[0_0_20px_rgba(255,255,255,0.2)]">{leadScore}%</p>
                </div>
                <div className="text-center group border-l-2 border-[#E10600]/30 pl-12 transition-all">
                  <p className="text-[12px] font-black text-slate-500 uppercase tracking-widest mb-4">MODE RÉPONSE</p>
                  <p className="text-7xl lg:text-8xl font-black text-[#E10600] drop-shadow-[0_0_20px_rgba(225,6,0,0.2)] uppercase">CLOSER</p>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* Exit & Controls */}
      <div className="absolute bottom-12 flex items-center gap-12 z-50">
         <button 
           onClick={handleClose} 
           className="group size-24 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all text-slate-400 shadow-2xl active:scale-90"
           title="Terminer la session FIKO™"
         >
           <X size={48} className="group-hover:rotate-90 transition-transform" />
         </button>
      </div>

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-10 text-white text-xs font-black uppercase tracking-[0.5em] flex items-center gap-10 shadow-[0_0_100px_#E10600] animate-in slide-in-from-top-4">
