function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(0);
  const [transcription, setTranscription] = useState("");
  const [emailInput, setEmailInput] = useState("");
  const [selectedPorte, setSelectedPorte] = useState("MARS");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close().catch(() => {});
    if (outputAudioContextRef.current) outputAudioContextRef.current.close().catch(() => {});
    if (sessionRef.current) { try { sessionRef.current.close(); } catch(e) {} }
    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) { int16[i] = data[i] * 32768; }
    return { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
  };

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active');
            setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 400)) + 5));
              sessionPromise.then(session => session.sendRealtimeInput({ media: createBlob(inputData) }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            const text = m.serverContent?.inputTranscription?.text?.toLowerCase() || "";
            if (text) {
              setTranscription(text);
              // Logic Detection for flow transitions
              if (text.includes("terra")) { setSelectedPorte("TERRA"); setFlowStep(FikoFlowStep.CLOSING_VALIDATION); }
              if (text.includes("mars")) { setSelectedPorte("MARS"); setFlowStep(FikoFlowStep.CLOSING_VALIDATION); }
              if (text.includes("krypton")) { setSelectedPorte("KRYPTON"); setFlowStep(FikoFlowStep.CLOSING_VALIDATION); }
              if (text.includes("oui") && flowStep === FikoFlowStep.CLOSING_VALIDATION) setFlowStep(FikoFlowStep.ACCOUNT_CREATION);
            }

            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 2, 100));
            }
          },
          onerror: () => { setError("ERREUR LIAISON NEURALE."); stopSession(); },
          onclose: () => stopSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: agent?.systemPrompt || ""
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ."); setStep('pre_start'); }
  };

  const handleManualEmailSubmit = () => {
    if (emailInput.includes("@")) {
      setFlowStep(FikoFlowStep.OFFER_CONFIRMATION);
      // Inform AI of the email
      sessionRef.current?.sendRealtimeInput([{ text: `L'email de l'utilisateur est ${emailInput}. Procède au récapitulatif de l'offre Porte ${selectedPorte}.` }]);
    }
  };

  const triggerCheckout = () => {
    setFlowStep(FikoFlowStep.ORDER_CHECKOUT);
    onOpenCheckout(selectedPorte);
    stopSession();
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      {/* CLOSE BUTTON */}
      <button onClick={onClose} className="absolute top-8 right-8 z-[110] group size-20 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all text-slate-400 active:scale-90">
        <X size={44} className="group-hover:rotate-90 transition-transform" />
      </button>

      {/* TUNNEL PROGRESS BAR */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-xl z-50 flex justify-between px-10">
        {[
          { id: FikoFlowStep.DISCOVERY, icon: <Activity size={14} />, label: 'DIAG' },
          { id: FikoFlowStep.CLOSING_VALIDATION, icon: <CheckCircle2 size={14} />, label: 'PORTE' },
          { id: FikoFlowStep.ACCOUNT_CREATION, icon: <UserPlus size={14} />, label: 'COMPTE' },
          { id: FikoFlowStep.OFFER_CONFIRMATION, icon: <CreditCard size={14} />, label: 'CHECK' }
        ].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-2 transition-all duration-700 ${flowStep === s.id ? 'opacity-100 scale-110' : 'opacity-30 scale-90'}`}>
            <div className={`size-10 rounded-full flex items-center justify-center border ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600] text-white shadow-[0_0_20px_rgba(225,6,0,0.5)]' : 'bg-white/5 border-white/20 text-white'}`}>
              {s.icon}
            </div>
            <span className="text-[8px] font-black uppercase tracking-widest">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="max-w-2xl w-full text-center space-y-16 animate-in zoom-in-95 duration-700 relative z-10">
          <div className="space-y-4">
             <div className="inline-block px-4 py-1 border border-[#E10600] text-[#E10600] text-[10px] font-black uppercase tracking-[0.6em] mb-8">SESSION STRATÉGIQUE KRYPTON AI</div>
             <h2 className="text-5xl lg:text-8xl font-black uppercase tracking-tighter leading-[0.8] text-white">Face-à-face <br/>avec <span className="text-[#E10600]">FIKO™.</span></h2>
          </div>
          <button onClick={startVocalSession} className="group relative bg-[#E10600] text-white px-16 py-8 rounded-sm font-black text-xs transition-all uppercase tracking-[0.5em] shadow-[0_0_100px_rgba(225,6,0,0.3)] hover:scale-105 active:scale-95 flex items-center gap-8 mx-auto">
            🎙️ Initialiser la liaison <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
          </button>
        </div>
      )}

      {step === 'connecting' && (
        <div className="flex flex-col items-center gap-16 animate-in fade-in duration-500">
           <Loader2 className="size-32 text-[#E10600] animate-spin" strokeWidth={1} />
           <p className="text-[12px] font-black uppercase tracking-[0.8em] text-[#E10600] animate-pulse">SYNCHRONISATION NEURALE...</p>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-7xl relative animate-in fade-in duration-1000">
           {/* Visual Waveform */}
           <div className="relative z-10 flex items-center justify-center gap-2 h-64 w-full">
            {bars.map((h, i) => (
              <div key={i} className="w-3 rounded-full bg-gradient-to-t from-red-950 via-[#E10600] to-white shadow-[0_0_20px_rgba(225,6,0,0.4)]" style={{ height: `${h}%`, opacity: (h / 100) * 0.4 + 0.6 }}></div>
            ))}
           </div>

           {/* Flow Specific Interactions */}
           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-xl">
              {flowStep === FikoFlowStep.DISCOVERY && (
                <div className="text-white text-xl font-light italic tracking-widest animate-pulse">"FIKO™ analyse vos besoins stratégiques..."</div>
              )}

              {flowStep === FikoFlowStep.CLOSING_VALIDATION && (
                <div className="bg-[#E10600]/10 border border-[#E10600]/30 p-8 rounded-sm space-y-6 animate-in slide-in-from-bottom-4">
                  <h4 className="text-[#E10600] font-black text-xs uppercase tracking-[0.4em]">SOLUTION RECOMMANDÉE</h4>
                  <p className="text-4xl font-black text-white tracking-tighter uppercase">PORTE {selectedPorte}</p>
                  <p className="text-slate-400 text-sm italic">"Souhaitez-vous activer ce palier de croissance ?"</p>
                  <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className="bg-white text-black px-10 py-4 font-black text-[10px] uppercase tracking-widest shadow-2xl hover:scale-105 transition-transform">OUI, ON AVANCE</button>
                </div>
              )}

              {flowStep === FikoFlowStep.ACCOUNT_CREATION && (
                <div className="bg-black/80 border border-white/10 p-10 rounded-sm space-y-8 animate-in zoom-in-95">
                  <div className="flex items-center gap-4 text-[#E10600] mb-4">
                    <Lock size={20} /> <span className="text-[10px] font-black uppercase tracking-[0.3em]">SÉCURISATION DE L'ESPACE CLIENT</span>
                  </div>
                  <input 
                    type="email" 
                    placeholder="VOTRE EMAIL PROFESSIONNEL" 
                    value={emailInput}
                    onChange={(e) => setEmailInput(e.target.value)}
                    className="w-full bg-black border border-white/20 p-6 text-white text-xs font-black uppercase tracking-[0.3em] outline-none focus:border-[#E10600]"
                  />
                  <button onClick={handleManualEmailSubmit} className="w-full bg-[#E10600] py-6 text-white font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-4">CRÉER MON ESPACE <ArrowRight size={16}/></button>
                </div>
              )}

              {flowStep === FikoFlowStep.OFFER_CONFIRMATION && (
                <div className="bg-[#E10600] p-12 rounded-sm text-white space-y-8 shadow-[0_0_100px_rgba(225,6,0,0.5)] animate-in slide-in-from-top-8">
                  <h4 className="font-black text-[10px] uppercase tracking-[0.5em] opacity-80">RÉCAPITULATIF EXÉCUTIF</h4>
                  <div className="text-left space-y-4">
                    <div className="flex justify-between border-b border-white/20 pb-4"><span>OFFRE</span> <span className="font-black">PORTE {selectedPorte}</span></div>
                    <div className="flex justify-between border-b border-white/20 pb-4"><span>STATUT</span> <span className="font-black">PRÊT AU CLOSING</span></div>
                    <div className="flex justify-between pb-4"><span>BUDGET</span> <span className="font-black">À PARTIR DE 500k FCFA</span></div>
                  </div>
                  <button onClick={triggerCheckout} className="w-full bg-white text-[#E10600] py-8 font-black text-xs uppercase tracking-[0.5em] hover:scale-105 transition-transform">FINALISER LA COMMANDE <CreditCard size={20}/></button>
                </div>
