              )}
           </div>

           <div className="absolute bottom-10 flex gap-20 items-center opacity-40">
              <div className="text-center"><p className="text-[10px] font-black text-slate-500 uppercase mb-1">INTENT</p><p className="text-2xl font-black text-white">{leadScore}%</p></div>
              <div className="text-center"><p className="text-[10px] font-black text-slate-500 uppercase mb-1">SECURE</p><p className="text-2xl font-black text-emerald-500">AES-512</p></div>
           </div>
        </div>
      )}

      {error && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[110] bg-[#E10600] p-10 text-white text-xs font-black uppercase tracking-[0.5em] flex items-center gap-10 shadow-[0_0_100px_#E10600] animate-in slide-in-from-top-4">
           <ShieldAlert size={40} /> <p className="text-lg font-bold uppercase">{error}</p>
        </div>
      )}
