function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(initialPorte ? 60 : 0);
  const [transcription, setTranscription] = useState("");

  // Account Form
  const [emailInput, setEmailInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close().catch(() => {});
    if (outputAudioContextRef.current) outputAudioContextRef.current.close().catch(() => {});
    if (sessionRef.current) { try { sessionRef.current.close(); } catch(e) {} }
    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active');
            setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 400)) + 5));
              sessionPromise.then(session => session.sendRealtimeInput({ media: { data: encode(new Uint8Array(new Int16Array(inputData.map(v => v * 32768)).buffer)), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // AUTO-INTRO BASED ON FLOW
            if (initialPorte) {
               sessionPromise.then(s => s.sendRealtimeInput([{ text: `L'utilisateur vient de choisir la PORTE ${initialPorte} sur le pricing. Ignore la qualification. Passe directement à la rassurance (État 1 du flow) et demande poliment l'email et un mot de passe pour sécuriser l'accès.` }]));
            } else {
               sessionPromise.then(s => s.sendRealtimeInput([{ text: "L'utilisateur est là. Lance ton diagnostic de qualification." }]));
            }
          },
          onmessage: async (m: LiveServerMessage) => {
            const text = m.serverContent?.inputTranscription?.text?.toLowerCase() || "";
            if (text) setTranscription(text);

            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 2, 100));
            }
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: agent?.systemPrompt || ""
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ."); setStep('pre_start'); }
  };

  const handleAccountSubmit = () => {
    if (emailInput.includes("@") && passwordInput.length > 5) {
      setFlowStep(FikoFlowStep.OFFER_CONFIRMATION);
      sessionRef.current?.sendRealtimeInput([{ text: `Espace client créé. Email: ${emailInput}. Mot de passe sécurisé. Récapitule l'offre Porte ${selectedPorte} pour validation finale.` }]);
    }
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6">
      <div className="absolute inset-0 hex-bg opacity-10"></div>

      {/* CLOSE BUTTON - TOP RIGHT */}
      <button onClick={onClose} className="absolute top-8 right-8 z-[110] group size-20 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all">
        <X size={44} />
      </button>

      {/* PROGRESS */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-xl z-50 flex justify-between px-10">
        {[
          { id: FikoFlowStep.DISCOVERY, label: 'QUALIF' },
          { id: FikoFlowStep.CLOSING_VALIDATION, label: 'VALID' },
          { id: FikoFlowStep.ACCOUNT_CREATION, label: 'COMPTE' },
          { id: FikoFlowStep.OFFER_CONFIRMATION, label: 'RECAP' }
        ].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-2 ${flowStep === s.id ? 'opacity-100' : 'opacity-20'}`}>
            <div className={`size-8 rounded-full border flex items-center justify-center text-[10px] font-black ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600]' : 'border-white/20'}`}>{i+1}</div>
            <span className="text-[8px] font-black tracking-widest">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10 animate-in zoom-in-95">
          <h2 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter text-white leading-none">
            {initialPorte ? `Porte ${initialPorte}` : 'Session'} <br/> <span className="text-[#E10600]">FIKO™.</span>
          </h2>
          <button onClick={startVocalSession} className="bg-[#E10600] text-white px-20 py-10 font-black text-xs uppercase tracking-[0.5em] shadow-2xl flex items-center gap-8 mx-auto hover:scale-105 active:scale-95 transition-all">
             🎙️ INITIALISER LE CLOSING
          </button>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-7xl relative">
           <div className="relative z-10 flex items-center justify-center gap-2 h-48 w-full">
            {bars.map((h, i) => (
              <div key={i} className="w-3 rounded-full bg-[#E10600] transition-all duration-150" style={{ height: `${h}%`, opacity: (h / 100) * 0.4 + 0.6 }}></div>
            ))}
           </div>

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-md">
              {flowStep === FikoFlowStep.CLOSING_VALIDATION && (
                <div className="bg-[#E10600] p-10 rounded-sm space-y-6 animate-in slide-in-from-bottom-4 shadow-[0_0_100px_rgba(225,6,0,0.4)]">
                  <h4 className="font-black text-[10px] uppercase tracking-[0.5em] text-white/70">VERROU PSYCHOLOGIQUE</h4>
                  <p className="text-4xl font-black text-white uppercase tracking-tighter">PORTE {selectedPorte}</p>
                  <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className="w-full bg-white text-black py-6 font-black text-[10px] uppercase tracking-widest">SÉCURISER CET ACCÈS</button>
                </div>
              )}

              {flowStep === FikoFlowStep.ACCOUNT_CREATION && (
                <div className="bg-black/80 border border-white/10 p-10 rounded-sm space-y-6 animate-in zoom-in-95 shadow-2xl">
                  <div className="flex items-center gap-4 text-[#E10600] justify-center mb-4">
                    <UserPlus size={20} /> <span className="text-[10px] font-black uppercase tracking-widest">ESPACE CLIENT SÉCURISÉ</span>
                  </div>
                  <div className="space-y-3">
                    <div className="relative">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                      <input type="email" placeholder="EMAIL PROFESSIONNEL" value={emailInput} onChange={e => setEmailInput(e.target.value)} className="w-full bg-black border border-white/10 p-5 pl-12 text-white text-xs font-black uppercase tracking-widest outline-none focus:border-[#E10600]" />
