              {flowStep === FikoFlowStep.OFFER_CONFIRMATION && (
                <div className="bg-[#E10600] p-12 rounded-sm text-white space-y-8 shadow-[0_0_100px_rgba(225,6,0,0.5)] animate-in slide-in-from-top-8">
                  <h4 className="font-black text-[10px] uppercase tracking-[0.5em] opacity-80">VALIDATION FINALE</h4>
                  <div className="text-left space-y-4 font-black text-xs uppercase tracking-widest">
                    <div className="flex justify-between border-b border-white/20 pb-4"><span>OFFRE</span> <span>PORTE {selectedPorte}</span></div>
                    <div className="flex justify-between border-b border-white/20 pb-4"><span>COMPTE</span> <span>VÉRIFIÉ</span></div>
                  </div>
                  <button onClick={() => onOpenCheckout(selectedPorte)} className="w-full bg-white text-[#E10600] py-8 font-black text-xs uppercase tracking-[0.5em]">FINALISER LA COMMANDE <ArrowRight size={20} className="inline ml-4"/></button>
                </div>
              )}

              {transcription && (
                 <div className="bg-white/5 border border-white/10 p-4 text-white font-mono text-[9px] uppercase tracking-widest opacity-40">"{transcription}"</div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

